class StandardScaler:
    def fit(self, X):
        n, d = len(X), len(X[0])
        self.mean_ = [sum(X[i][j] for i in range(n))/n for j in range(d)]
        self.std_  = [max(1e-8, (sum((X[i][j]-self.mean_[j])**2 for i in range(n))/n)**0.5)
                      for j in range(d)]
        return self
    def transform(self, X):
        return [[(X[i][j] - self.mean_[j]) / self.std_[j]
                 for j in range(len(X[i]))] for i in range(len(X))]

class MinMaxScaler:
    def fit(self, X):
        d = len(X[0])
        self.min_  = [min(X[i][j] for i in range(len(X))) for j in range(d)]
        self.range_= [max(max(X[i][j] for i in range(len(X))) - self.min_[j], 1e-8)
                      for j in range(d)]
        return self
    def transform(self, X):
        return [[(X[i][j] - self.min_[j]) / self.range_[j]
                 for j in range(len(X[i]))] for i in range(len(X))]

